import{_ as e,o as s,c as i,ac as n}from"./chunks/framework.DnBnwVZk.js";const k=JSON.parse('{"title":"命令行申请证书","description":"","frontmatter":{"date":"2024-12-04T13:35:00.000Z","categories":["Linux"],"tags":["Linux","Self Host"],"publish":true},"headers":[],"relativePath":"views/linux/nas/ShellCert.md","filePath":"views/linux/nas/ShellCert.md","lastUpdated":1775714960000}'),t={name:"views/linux/nas/ShellCert.md"};function l(h,a,r,c,o,p){return s(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1733319300000"},[...a[0]||(a[0]=[n(`<h1 id="命令行申请证书" tabindex="-1">命令行申请证书 <a class="header-anchor" href="#命令行申请证书" aria-label="Permalink to &quot;命令行申请证书&quot;">​</a></h1><h2 id="下载acme-sh" tabindex="-1">下载acme.sh <a class="header-anchor" href="#下载acme-sh" aria-label="Permalink to &quot;下载acme.sh&quot;">​</a></h2><p>参考<a href="https://github.com/acmesh-official/acme.sh/wiki/Install-in-China" target="_blank" rel="noreferrer">教程</a></p><h2 id="配置dns" tabindex="-1">配置DNS <a class="header-anchor" href="#配置dns" aria-label="Permalink to &quot;配置DNS&quot;">​</a></h2><p>以HE为例</p><p>在<code>~/.acme.sh/account.conf</code>文件中增加下列配置</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export HE_Usernmae=&#39;username&#39;</span></span>
<span class="line"><span>export HE_Password=&#39;password&#39;</span></span></code></pre></div><p>其他服务商见<a href="https://github.com/acmesh-official/acme.sh/wiki/dnsapi" target="_blank" rel="noreferrer">Github</a></p><h2 id="签发" tabindex="-1">签发 <a class="header-anchor" href="#签发" aria-label="Permalink to &quot;签发&quot;">​</a></h2><p><code>./acme.sh --issue -d YOUR.com -d &#39;*.YOUR.com&#39; -k ec-256 --dns dns_he --dnssleep 60</code></p><h2 id="安装证书到指定位置" tabindex="-1">安装证书到指定位置 <a class="header-anchor" href="#安装证书到指定位置" aria-label="Permalink to &quot;安装证书到指定位置&quot;">​</a></h2><p><code>./acme.sh --install-cert -d YOUR.com --ecc --key-file /etc/nginx/ssl/YOUR.com.key --fullchain-file /etc/nginx/ssl/YOUR.com_fullchain.cer --reloadcmd &quot;docker restart nginx&quot;</code></p><h2 id="检查cron表达式是否有效" tabindex="-1">检查CRON表达式是否有效 <a class="header-anchor" href="#检查cron表达式是否有效" aria-label="Permalink to &quot;检查CRON表达式是否有效&quot;">​</a></h2><p><code>./acme.sh --cron</code></p><h2 id="自动更新证书" tabindex="-1">自动更新证书 <a class="header-anchor" href="#自动更新证书" aria-label="Permalink to &quot;自动更新证书&quot;">​</a></h2><p>脚本会把自己添加到crontab里自动运行，不需要额外处理</p><h2 id="手动更新证书" tabindex="-1">手动更新证书 <a class="header-anchor" href="#手动更新证书" aria-label="Permalink to &quot;手动更新证书&quot;">​</a></h2><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 更新一个证书</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">acme.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --renew</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ecc</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 更新所有证书</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">acme.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --renew-all</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 运行 cronjob 来更新证书（可用于检查 cronjob 命令是否正确）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">acme.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cron</span></span></code></pre></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://blog.dalutou.com/posts/issue-a-free-wildcard-ssl-certificate-with-acme-sh/" target="_blank" rel="noreferrer">使用 acme.sh 签发免费的通配符 SSL 证书</a></li></ul>`,20)])])}const u=e(t,[["render",l]]);export{k as __pageData,u as default};
